import InputForm from "../Components/Input/InputForm";

function IdentificationPage() {
  return (
    <div style={{
    position: "absolute", 
    display:"flex",
    flexDirection: "column",
    right: "0", 
    top: "50%", 
    transform: "translateY(-50%)",
    maxWidth: "720px",
    maxHeight: "745px",
    justifyContent:"center",
    alignItems: "center",
    width: "100%",
    height: "100%"
    
    }}>
    <p style={{display:"flex", justifyContent:"center"}}>Выполните вход чтобы продолжить</p>
    <InputForm TextPlaceholder="Адрес электронной почты"/>
    <InputForm TextPlaceholder={"Пароль"}/>
    </div>
  );
}

export default IdentificationPage;
